import "./ShowingCard.css";
import React, { lazy, useEffect } from "react";
import { getAllUsers } from "../../actions/UserAction";
import { useSelector, useDispatch } from "react-redux";
const UserCard = lazy(() => import("../UserCard/UserCard"));

function ShowingCard() {
  const { user } = useSelector((state) => state.AuthReducer.authData);
  const { users } = useSelector((state) => state.UserReducer);
  const dispatch = useDispatch();

  useEffect(() => {
    const fetchUsers = () => {
      dispatch(getAllUsers());
    };
    fetchUsers();
  }, []);

  return (
    <div className="following-card">
      {users && users.length > 1 && <h3>اقتراحات</h3>}
      {users &&
        users.map((userCard, id) => {
          if (userCard._id !== user._id)
            return <UserCard user={userCard} key={userCard._id} />;
          return "";
        })}
    </div>
  );
}
export default ShowingCard;
